export const thirdPartyAuthTokensInfiniteQueryKey = (
    options?: Options<ThirdPartyAuthTokensData>,
): QueryKey<Options<ThirdPartyAuthTokensData>> =>
    createQueryKey('thirdPartyAuthTokens', options, true);

/**
 * List third-party auth tokens
 */
export const thirdPartyAuthTokensInfiniteOptions = (
    options?: Options<ThirdPartyAuthTokensData>,
) => {
    const opts = infiniteQueryOptions<
        ThirdPartyAuthTokensResponse,
        ThirdPartyAuthTokensError,
        InfiniteData<ThirdPartyAuthTokensResponse>,
        QueryKey<Options<ThirdPartyAuthTokensData>>,
        | number
        | Pick<
              QueryKey<Options<ThirdPartyAuthTokensData>>[0],
              'body' | 'headers' | 'path' | 'query'
          >
    >(
        // @ts-ignore
        {
            queryFn: async ({ pageParam, queryKey, signal }) => {
                // @ts-ignore
                const page: Pick<
                    QueryKey<Options<ThirdPartyAuthTokensData>>[0],
                    'body' | 'headers' | 'path' | 'query'
                > =
                    typeof pageParam === 'object'
                        ? pageParam
                        : {
                              query: {
                                  page: pageParam,
                              },
                          };
                const params = createInfiniteParams(queryKey, page);
                const { data } = await thirdPartyAuthTokens({
                    ...options,
                    ...params,
                    signal,
                    throwOnError: true,
                });
                return data;
            },
            queryKey: thirdPartyAuthTokensInfiniteQueryKey(options),
        },
    );
    return opts as Omit<typeof opts, 'initialData'>;
};

